    // ✅ Range-based for (preferred)
    for (int num : numbers) {
        std::cout << num << " ";
    }
    std::cout << "\n";

    // ✅ Iterator-based
    for (auto it = numbers.begin(); it != numbers.end(); ++it) {
        std::cout << *it << " ";
    }
    std::cout << "\n";

    // ✅ Index-based (less common)
    for (size_t i = 0; i < numbers.size(); ++i) {
        // No operator[], must use iterators
